MERGE INTO CONSULTAS FIN USING (SELECT '002383Conciliacionbancaria' INFORME ,TO_CLOB(q'[SELECT  COMPANIA, CODIGO, SALDOs$mes$s AS SALDOCONTABLE, SALDOs$mesAnterior$s AS SALDOCONTABLEANTERIOR
FROM    PLAN_CONTABLE
WHERE   COMPANIA = s$compania$s
AND     ANO = s$ano$s
AND     CODIGO = 's$cuenta$s']') CONSULTA, 1 APLICACION ,TO_CLOB(q'[]') CONSULTA_OPCIONAL, 'mrosero' CREATED_BY, NULL MODIFIED_BY  FROM DUAL ) INI ON (INI.INFORME = FIN.INFORME )  WHEN MATCHED THEN  UPDATE SET FIN.CONSULTA =  INI.CONSULTA, FIN.APLICACION =  INI.APLICACION, FIN.CONSULTA_OPCIONAL =  INI.CONSULTA_OPCIONAL, FIN.MODIFIED_BY = INI.MODIFIED_BY, FIN.DATE_MODIFIED = SYSDATE  WHEN NOT MATCHED THEN  INSERT (INFORME,CONSULTA, APLICACION,CONSULTA_OPCIONAL,CREATED_BY,DATE_CREATED)  VALUES (INI.INFORME,INI.CONSULTA, INI.APLICACION,INI.CONSULTA_OPCIONAL,INI.CREATED_BY,SYSDATE);